                "ParentID",
                "Comments"
            )
        VALUES
            (
                p_ID,
                p_AgentRunID,
                p_StepNumber,
                COALESCE(p_StepType, 'Prompt'),
                p_StepName,
                CASE WHEN p_TargetID_Clear = TRUE THEN NULL ELSE COALESCE(p_TargetID, NULL) END,
                COALESCE(p_Status, 'Running'),
