    IN p_Height INTEGER DEFAULT NULL,
    IN p_Status VARCHAR(20) DEFAULT NULL,
    IN p_ActionInputMapping_Clear BOOLEAN DEFAULT FALSE,
    IN p_ActionInputMapping TEXT DEFAULT NULL,
    IN p_LoopBodyType_Clear BOOLEAN DEFAULT FALSE,
    IN p_LoopBodyType VARCHAR(50) DEFAULT NULL,
    IN p_Configuration_Clear BOOLEAN DEFAULT FALSE,
    IN p_Configuration TEXT DEFAULT NULL
)
RETURNS SETOF __mj."vwAIAgentSteps" AS
$$
DECLARE
    _v_row_count INTEGER;
BEGIN
UPDATE
        __mj."AIAgentStep"
    SET
        "AgentID" = COALESCE(p_AgentID, "AgentID"),
        "Name" = COALESCE(p_Name, "Name"),
        "Description" = CASE WHEN p_Description_Clear = TRUE THEN NULL ELSE COALESCE(p_Description, "Description") END,
        "StepType" = COALESCE(p_StepType, "StepType"),
        "StartingStep" = COALESCE(p_StartingStep, "StartingStep"),
        "TimeoutSeconds" = CASE WHEN p_TimeoutSeconds_Clear = TRUE THEN NULL ELSE COALESCE(p_TimeoutSeconds, "TimeoutSeconds") END,
        "RetryCount" = COALESCE(p_RetryCount, "RetryCount"),
        "OnErrorBehavior" = COALESCE(p_OnErrorBehavior, "OnErrorBehavior"),
        "ActionID" = CASE WHEN p_ActionID_Clear = TRUE THEN NULL ELSE COALESCE(p_ActionID, "ActionID") END,
        "SubAgentID" = CASE WHEN p_SubAgentID_Clear = TRUE THEN NULL ELSE COALESCE(p_SubAgentID, "SubAgentID") END,
        "PromptID" = CASE WHEN p_PromptID_Clear = TRUE THEN NULL ELSE COALESCE(p_PromptID, "PromptID") END,
        "ActionOutputMapping" = CASE WHEN p_ActionOutputMapping_Clear = TRUE THEN NULL ELSE COALESCE(p_ActionOutputMapping, "ActionOutputMapping") END,
        "PositionX" = COALESCE(p_PositionX, "PositionX"),
        "PositionY" = COALESCE(p_PositionY, "PositionY"),
        "Width" = COALESCE(p_Width, "Width"),
        "Height" = COALESCE(p_Height, "Height"),
        "Status" = COALESCE(p_Status, "Status"),
        "ActionInputMapping" = CASE WHEN p_ActionInputMapping_Clear = TRUE THEN NULL ELSE COALESCE(p_ActionInputMapping, "ActionInputMapping") END,
        "LoopBodyType" = CASE WHEN p_LoopBodyType_Clear = TRUE THEN NULL ELSE COALESCE(p_LoopBodyType, "LoopBodyType") END,
        "Configuration" = CASE WHEN p_Configuration_Clear = TRUE THEN NULL ELSE COALESCE(p_Configuration, "Configuration") END
    WHERE
        "ID" = p_ID;

    GET DIAGNOSTICS _v_row_count = ROW_COUNT;

    IF _v_row_count = 0 THEN
        RETURN QUERY SELECT * FROM __mj."vwAIAgentSteps" WHERE 1=0;
    ELSE
        RETURN QUERY SELECT * FROM __mj."vwAIAgentSteps" WHERE "ID" = p_ID;
    END IF;
END;
$$ LANGUAGE plpgsql;

