CREATE OR REPLACE FUNCTION __mj."spCreateAIArchitecture"(
    IN p_ID UUID DEFAULT NULL,
    IN p_Name VARCHAR(100) DEFAULT NULL,
    IN p_Description_Clear BOOLEAN DEFAULT FALSE,
    IN p_Description TEXT DEFAULT NULL,
    IN p_Category VARCHAR(50) DEFAULT NULL,
    IN p_ParentArchitectureID_Clear BOOLEAN DEFAULT FALSE,
    IN p_ParentArchitectureID UUID DEFAULT NULL,
    IN p_WikipediaURL_Clear BOOLEAN DEFAULT FALSE,
    IN p_WikipediaURL VARCHAR(500) DEFAULT NULL,
    IN p_YearIntroduced_Clear BOOLEAN DEFAULT FALSE,
    IN p_YearIntroduced INTEGER DEFAULT NULL,
    IN p_KeyPaper_Clear BOOLEAN DEFAULT FALSE,
    IN p_KeyPaper VARCHAR(500) DEFAULT NULL
)
RETURNS SETOF __mj."vwAIArchitectures" AS
$$
BEGIN
IF p_ID IS NOT NULL THEN
        -- User provided a value, use it
        INSERT INTO __mj."AIArchitecture"
            (
                "ID",
                "Name",
                "Description",
                "Category",
                "ParentArchitectureID",
                "WikipediaURL",
                "YearIntroduced",
                "KeyPaper"
            )
        VALUES
            (
                p_ID,
                p_Name,
                CASE WHEN p_Description_Clear = TRUE THEN NULL ELSE COALESCE(p_Description, NULL) END,
                p_Category,
                CASE WHEN p_ParentArchitectureID_Clear = TRUE THEN NULL ELSE COALESCE(p_ParentArchitectureID, NULL) END,
                CASE WHEN p_WikipediaURL_Clear = TRUE THEN NULL ELSE COALESCE(p_WikipediaURL, NULL) END,
                CASE WHEN p_YearIntroduced_Clear = TRUE THEN NULL ELSE COALESCE(p_YearIntroduced, NULL) END,
                CASE WHEN p_KeyPaper_Clear = TRUE THEN NULL ELSE COALESCE(p_KeyPaper, NULL) END
            );
    ELSE
        -- No value provided, let database use its default (e.g., gen_random_uuid())
        INSERT INTO __mj."AIArchitecture"
            (
                "Name",
                "Description",
                "Category",
                "ParentArchitectureID",
                "WikipediaURL",
                "YearIntroduced",
                "KeyPaper"
            )
        VALUES
            (
                p_Name,
                CASE WHEN p_Description_Clear = TRUE THEN NULL ELSE COALESCE(p_Description, NULL) END,
                p_Category,
                CASE WHEN p_ParentArchitectureID_Clear = TRUE THEN NULL ELSE COALESCE(p_ParentArchitectureID, NULL) END,
                CASE WHEN p_WikipediaURL_Clear = TRUE THEN NULL ELSE COALESCE(p_WikipediaURL, NULL) END,
                CASE WHEN p_YearIntroduced_Clear = TRUE THEN NULL ELSE COALESCE(p_YearIntroduced, NULL) END,
                CASE WHEN p_KeyPaper_Clear = TRUE THEN NULL ELSE COALESCE(p_KeyPaper, NULL) END
            );
    END IF;
    -- return the new record from the base view, which might have some calculated fields
    RETURN QUERY SELECT * FROM __mj."vwAIArchitectures" WHERE "ID" = p_ID;
END;
$$ LANGUAGE plpgsql;

