CREATE OR REPLACE FUNCTION __mj."spCreateAIResultCache"(
    IN p_ID UUID DEFAULT NULL,
    IN p_AIPromptID UUID DEFAULT NULL,
    IN p_AIModelID UUID DEFAULT NULL,
    IN p_RunAt TIMESTAMPTZ DEFAULT NULL,
    IN p_PromptText TEXT DEFAULT NULL,
    IN p_ResultText_Clear BOOLEAN DEFAULT FALSE,
    IN p_ResultText TEXT DEFAULT NULL,
    IN p_Status VARCHAR(50) DEFAULT NULL,
    IN p_ExpiredOn_Clear BOOLEAN DEFAULT FALSE,
    IN p_ExpiredOn TIMESTAMPTZ DEFAULT NULL,
    IN p_VendorID_Clear BOOLEAN DEFAULT FALSE,
    IN p_VendorID UUID DEFAULT NULL,
    IN p_AgentID_Clear BOOLEAN DEFAULT FALSE,
    IN p_AgentID UUID DEFAULT NULL,
    IN p_ConfigurationID_Clear BOOLEAN DEFAULT FALSE,
    IN p_ConfigurationID UUID DEFAULT NULL,
    IN p_PromptEmbedding_Clear BOOLEAN DEFAULT FALSE,
    IN p_PromptEmbedding BYTEA DEFAULT NULL,
    IN p_PromptRunID_Clear BOOLEAN DEFAULT FALSE,
    IN p_PromptRunID UUID DEFAULT NULL
)
RETURNS SETOF __mj."vwAIResultCaches" AS
$$
BEGIN
IF p_ID IS NOT NULL THEN
        -- User provided a value, use it
        INSERT INTO __mj."AIResultCache"
            (
                "ID",
                "AIPromptID",
                "AIModelID",
                "RunAt",
                "PromptText",
                "ResultText",
                "Status",
                "ExpiredOn",
                "VendorID",
                "AgentID",
                "ConfigurationID",
                "PromptEmbedding",
                "PromptRunID"
            )
        VALUES
            (
                p_ID,
                p_AIPromptID,
                p_AIModelID,
                p_RunAt,
                p_PromptText,
                CASE WHEN p_ResultText_Clear = TRUE THEN NULL ELSE COALESCE(p_ResultText, NULL) END,
                p_Status,
                CASE WHEN p_ExpiredOn_Clear = TRUE THEN NULL ELSE COALESCE(p_ExpiredOn, NULL) END,
                CASE WHEN p_VendorID_Clear = TRUE THEN NULL ELSE COALESCE(p_VendorID, NULL) END,
                CASE WHEN p_AgentID_Clear = TRUE THEN NULL ELSE COALESCE(p_AgentID, NULL) END,
                CASE WHEN p_ConfigurationID_Clear = TRUE THEN NULL ELSE COALESCE(p_ConfigurationID, NULL) END,
                CASE WHEN p_PromptEmbedding_Clear = TRUE THEN NULL ELSE COALESCE(p_PromptEmbedding, NULL) END,
                CASE WHEN p_PromptRunID_Clear = TRUE THEN NULL ELSE COALESCE(p_PromptRunID, NULL) END
            );
    ELSE
        -- No value provided, let database use its default (e.g., gen_random_uuid())
        INSERT INTO __mj."AIResultCache"
            (
                "AIPromptID",
                "AIModelID",
                "RunAt",
                "PromptText",
                "ResultText",
                "Status",
                "ExpiredOn",
                "VendorID",
                "AgentID",
                "ConfigurationID",
                "PromptEmbedding",
                "PromptRunID"
            )
        VALUES
            (
                p_AIPromptID,
                p_AIModelID,
                p_RunAt,
                p_PromptText,
                CASE WHEN p_ResultText_Clear = TRUE THEN NULL ELSE COALESCE(p_ResultText, NULL) END,
                p_Status,
                CASE WHEN p_ExpiredOn_Clear = TRUE THEN NULL ELSE COALESCE(p_ExpiredOn, NULL) END,
                CASE WHEN p_VendorID_Clear = TRUE THEN NULL ELSE COALESCE(p_VendorID, NULL) END,
                CASE WHEN p_AgentID_Clear = TRUE THEN NULL ELSE COALESCE(p_AgentID, NULL) END,
                CASE WHEN p_ConfigurationID_Clear = TRUE THEN NULL ELSE COALESCE(p_ConfigurationID, NULL) END,
                CASE WHEN p_PromptEmbedding_Clear = TRUE THEN NULL ELSE COALESCE(p_PromptEmbedding, NULL) END,
                CASE WHEN p_PromptRunID_Clear = TRUE THEN NULL ELSE COALESCE(p_PromptRunID, NULL) END
            );
    END IF;
    -- return the new record from the base view, which might have some calculated fields
    RETURN QUERY SELECT * FROM __mj."vwAIResultCaches" WHERE "ID" = p_ID;
END;
$$ LANGUAGE plpgsql;

